// src/three/utils/GridHelper.js - Simplified version

import * as THREE from 'three';

export class GridHelper {
  constructor(size = 20, divisions = 20, spacing = 1.0) {
    this.createGrid(size, divisions, spacing);
  }
  
  createGrid(size, divisions, spacing) {
    // Create a group to hold our custom grid
    const gridGroup = new THREE.Group();
    
    // Create a plane for the floor
    const floorGeometry = new THREE.PlaneGeometry(size, size);
    const floorMaterial = new THREE.MeshBasicMaterial({ 
      color: 0xffffff,
      transparent: true,
      opacity: 0.1,
      side: THREE.DoubleSide
    });
    const floor = new THREE.Mesh(floorGeometry, floorMaterial);
    floor.rotation.x = Math.PI / 2; // Rotate to be horizontal
    floor.position.y = 0;
    gridGroup.add(floor);
    
    // Create grid lines (without axes)
    const color = 0x888888;
    const step = size / divisions;
    
    const lineGeometry = new THREE.BufferGeometry();
    const lineMaterial = new THREE.LineBasicMaterial({ color: color, opacity: 0.3, transparent: true });
    
    const points = [];
    
    // Create grid lines
    const halfSize = size / 2;
    
    // Add X grid lines (along Z axis)
    for (let i = -halfSize; i <= halfSize; i += step) {
      points.push(new THREE.Vector3(-halfSize, 0, i));
      points.push(new THREE.Vector3(halfSize, 0, i));
    }
    
    // Add Z grid lines (along X axis)
    for (let i = -halfSize; i <= halfSize; i += step) {
      points.push(new THREE.Vector3(i, 0, -halfSize));
      points.push(new THREE.Vector3(i, 0, halfSize));
    }
    
    // Convert points to buffer geometry
    const vertices = new Float32Array(points.length * 3);
    for (let i = 0; i < points.length; i++) {
      vertices[i * 3] = points[i].x;
      vertices[i * 3 + 1] = points[i].y;
      vertices[i * 3 + 2] = points[i].z;
    }
    
    lineGeometry.setAttribute('position', new THREE.BufferAttribute(vertices, 3));
    
    // Create the grid lines
    const lines = new THREE.LineSegments(lineGeometry, lineMaterial);
    lines.position.y = 0.01; // Slightly above floor to prevent z-fighting
    
    gridGroup.add(lines);
    
    // Store reference to our grid
    this.grid = gridGroup;
  }
  
  // Method to toggle grid visibility
  setVisible(visible) {
    if (this.grid) {
      this.grid.visible = visible;
    }
  }
}
